class UnionFind {
public:
    vector<int> parent;
    vector<int> size;
    int count;

    UnionFind(int n) {
        parent.resize(n);
        size.resize(n, 1);
        count = n;
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unionSet(int x, int y) {
        int rootX = find(x);
        int rootY = find(y);
        if (rootX != rootY) {
            if (size[rootX] < size[rootY]) {
                parent[rootX] = rootY;
                size[rootY] += size[rootX];
            } else {
                parent[rootY] = rootX;
                size[rootX] += size[rootY];
            }
            count--;
        }
    }
};

class Solution {
public:
    int numberOfGoodPaths(vector<int>& vals, vector<vector<int>>& edges) {
        int n = vals.size();
        vector<vector<int>> graph(n);
        for (auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            graph[edge[1]].push_back(edge[0]);
        }

        vector<vector<int>> nodes(n);
        for (int i = 0; i < n; i++) {
            nodes[i].push_back(i);
        }

        sort(nodes.begin(), nodes.end(), [&](const vector<int>& a, const vector<int>& b) {
            return vals[a[0]] < vals[b[0]];
        });

        UnionFind uf(n);
        int result = n;
        for (auto& node : nodes) {
            for (int neighbor : graph[node[0]]) {
                if (vals[neighbor] <= vals[node[0]]) {
                    if (uf.find(neighbor) != uf.find(node[0])) {
                        result += uf.size[uf.find(node[0])] * uf.size[uf.find(neighbor)];
                        uf.unionSet(node[0], neighbor);
                    }
                }
            }
        }
        return result;
    }
};
